const sales = $input.first().json;
const todaySales = sales.totalSales || 0;
const avgSales = sales.sevenDayAvg || 0;

if (avgSales === 0) return [];

const deviation = ((todaySales - avgSales) / avgSales) * 100;
const absDeviation = Math.abs(deviation);

if (absDeviation < 20) return [];

const direction = deviation > 0 ? '📈 SPIKE' : '📉 DROP';
const today = new Date().toLocaleDateString('en-IN', {day:'2-digit',month:'short'});
const time = new Date().toLocaleTimeString('en-IN', {hour:'2-digit',minute:'2-digit'});

const msg = `*V2 Retail Sales Alert — ${today} ${time}*

${direction}: ${deviation > 0 ? '+' : ''}${deviation.toFixed(1)}% vs 7-day avg

Today: ₹${todaySales.toLocaleString('en-IN')}
7-day avg: ₹${avgSales.toLocaleString('en-IN')}
Diff: ₹${Math.abs(todaySales - avgSales).toLocaleString('en-IN')}`;

return [{ json: { message: msg, deviation: deviation.toFixed(1) } }];

const event = $input.first().json;
const status = event.workflow_run?.conclusion || event.action || 'triggered';
const branch = event.workflow_run?.head_branch || 'master';
const commitMsg = (event.workflow_run?.head_commit?.message || '').slice(0, 80);
const icon = status === 'success' ? '✅' : status === 'failure' ? '❌' : '⏳';

const msg = `*RFC API Deploy ${icon}*

Status: ${status}
Branch: ${branch}
Commit: ${commitMsg}
Time: ${new Date().toLocaleTimeString('en-IN', {hour:'2-digit',minute:'2-digit'})}`;

return [{ json: { message: msg } }];
